import axios, { AxiosError } from 'axios';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001/api';

const api = axios.create({
  baseURL: API_URL,
  withCredentials: true,
  timeout: 10000,
});

let csrfToken: string | null = null;

// Función para obtener token CSRF
const getCsrfToken = async (): Promise<string> => {
  if (csrfToken) return csrfToken;

  try {
    const response = await axios.get(`${API_URL}/csrf-token`, { withCredentials: true });
    csrfToken = response.data.csrfToken;
    return csrfToken;
  } catch (error) {
    console.error('Error obteniendo CSRF token:', error);
    throw new Error('Error de seguridad');
  }
};

// Interceptor para agregar token y CSRF a las requests
api.interceptors.request.use(async (config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }

  // Agregar CSRF token para requests que modifican datos
  if (config.method && ['post', 'put', 'delete'].includes(config.method.toLowerCase())) {
    try {
      const csrf = await getCsrfToken();
      config.headers['X-CSRF-Token'] = csrf;
    } catch (error) {
      console.error('Error agregando CSRF token:', error);
    }
  }

  return config;
}, (error) => {
  return Promise.reject(error);
});

// Interceptor para manejar respuestas y errores
api.interceptors.response.use(
  (response) => response,
  (error: AxiosError) => {
    if (error.response?.status === 401) {
      // Token expirado o inválido
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      csrfToken = null;
      window.location.href = '/login';
    }

    // Mejorar mensajes de error
    const errorMessage = error.response?.data?.error || error.message || 'Error desconocido';
    return Promise.reject(new Error(errorMessage));
  }
);

export const authService = {
  async login(email: string, password: string) {
    try {
      const response = await api.post('/auth/login', { email, password });
      const { token, user } = response.data;

      localStorage.setItem('token', token);
      localStorage.setItem('user', JSON.stringify(user));

      return response.data;
    } catch (error) {
      console.error('Error en login:', error);
      throw error;
    }
  },

  async verifyToken() {
    try {
      const response = await api.get('/auth/verify');
      return response.data.user;
    } catch (error) {
      console.error('Error verificando token:', error);
      throw error;
    }
  },

  logout() {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    csrfToken = null;
  }
};

export default api;
